import Logo from '../../logo.png';
import NavigationList from '../navigation/navigation-list';
import './header.css';

const Header = () => {
    return(        
        <header className="row">   
            <div className='col-10'>
                <h1>NPTFC Tigers</h1>
            </div>
            <div className='col-1'>
                <img src={Logo} className="App-logo" alt="logo"></img>
            </div>
        </header>        
    );
}
export default Header;
